const body = $json.body || $json;
const termo = String(body.termo || body.produto || body.categoria || '').trim();
return [{ json: { termo, limite: Number(body.limite || 5) } }];

const produtos = $input.all().map(i => i.json);
let texto;
if (!produtos.length) {
  texto = 'Não encontrei esse item no catálogo agora. Deseja que eu chame um atendente para verificar disponibilidade?';
} else {
  texto = 'Encontrei estes produtos no catálogo:\n\n' + produtos.map((p, idx) => `${idx + 1}. ${p.name} - R$ ${Number(p.price).toFixed(2)}\n${p.description || ''}${p.image_url ? `\nImagem: ${p.image_url}` : ''}`).join('\n\n');
}
return [{ json: { produtos, texto } }];
